def _select_tip_with_weights(self):
    """Select a tip key from TIPS, optionally biased by self.tip_weights.

    When self.tip_weights is None, this preserves the original uniform draw. Otherwise,
    weights are normalized into probabilities and a tip is selected using self.rng.random()
    against the cumulative distribution, so selection remains deterministic for a fixed seed.
    """
    tip_keys = list(TIPS.keys())

    if self.tip_weights is None:
        return self.rng.choice(tip_keys)

    weights = [max(self.tip_weights.get(key, 1.0), 0.0) for key in tip_keys]
    total_weight = sum(weights)
    if total_weight <= 0:
        return self.rng.choice(tip_keys)

    threshold = self.rng.random()
    cumulative = 0.0
    for key, weight in zip(tip_keys, weights):
        cumulative += weight / total_weight
        if threshold < cumulative:
            return key

    return tip_keys[-1]

def _trim_to_sentence_boundary(self, instruction):
    """Trim instruction to fit under max_instr_chars, preferring the last sentence boundary."""
    limit = self.max_instr_chars - 1
    window = instruction[:limit]

    boundary_idx = -1
    for punct in (".", "!", "?"):
        idx = window.rfind(punct)
        if idx > boundary_idx:
            boundary_idx = idx

    if boundary_idx != -1:
        return instruction[:boundary_idx + 1] + "…"

    return window + "…"

def _enforce_instruction_length_bounds(self, proposed_instruction, predictor):
    """Ensure a proposed instruction falls within [min_instr_chars, max_instr_chars]."""
    length = len(proposed_instruction)

    if length < self.min_instr_chars:
        basic_instruction = get_signature(predictor).instructions
        if self.verbose:
            print(
                f"Proposed instruction length ({length}) is below min_instr_chars "
                f"({self.min_instr_chars}). Falling back to the predictor's basic instruction.",
            )
        return basic_instruction

    if length > self.max_instr_chars:
        if self.rephrase_when_too_long:
            if self.verbose:
                print(
                    f"Proposed instruction length ({length}) exceeds max_instr_chars "
                    f"({self.max_instr_chars}). Rephrasing via ShortenInstruction.",
                )
            shorten = dspy.Predict(ShortenInstruction)
            with dspy.settings.context(lm=self.prompt_model):
                shortened_instruction = strip_prefix(
                    shorten(
                        instruction=proposed_instruction,
                        max_chars=str(self.max_instr_chars),
                    ).proposed_instruction,
                )
            if len(shortened_instruction) > self.max_instr_chars:
                shortened_instruction = shortened_instruction[: self.max_instr_chars]
            return shortened_instruction
        else:
            if self.verbose:
                print(
                    f"Proposed instruction length ({length}) exceeds max_instr_chars "
                    f"({self.max_instr_chars}). Trimming at the last sentence boundary.",
                )
            return self._trim_to_sentence_boundary(proposed_instruction)

    return proposed_instruction

